solution: ```class Solution {
public:
    vector<string> findRepeatedDnaSequences(string s) {
        if (s.size() < 11) return {};
        unordered_map<int, int> seen;
        vector<string> ans;
        int key = 0;
        for (int i = 0; i < 9; ++i) {
            key = (key << 2) | ((s[i] >> 1) & 3);
        }
        for (int i = 9; i < s.size(); ++i) {
            key = ((key << 2) & 0xFFFFF) | ((s[i] >> 1) & 3);
            if (++seen[key] == 2) {
                ans.push_back(s.substr(i - 9, 10));
            }
        }
        return ans;
    }
};
